td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;45&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token function&#34;&gt;print&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;v&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;46&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;end&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;47&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;end&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;48&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;49&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;-- output&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;50&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;------------------------&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;51&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;num&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;52&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;53&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token number&#34;&gt;2&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;54&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token number&#34;&gt;3&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;55&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token number&#34;&gt;4&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;56&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;str&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;57&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;str1&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;58&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;str2&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;59&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;lua&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;60&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token operator&#34;&gt;//&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;//&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;//&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;//&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;//&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;//&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;//&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;//&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;//&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;//&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;//&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;//&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;61&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token number&#34;&gt;2&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;62&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;63&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token number&#34;&gt;2&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;64&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token number&#34;&gt;3&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;65&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token number&#34;&gt;4&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;66&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;67&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;str1&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;68&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;str2&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;69&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;lua&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;70&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token operator&#34;&gt;==&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;==&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;==&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;==&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;==&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;==&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;==&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;==&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;==&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;==&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;==&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;==&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;71&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;72&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;73&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;str1&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;74&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;str2&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;75&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token number&#34;&gt;2&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;76&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;77&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token number&#34;&gt;2&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;78&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token number&#34;&gt;3&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;79&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token number&#34;&gt;4&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;80&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;-- 可以看出 ipairs 对于 key 值为 string 的时候无法进行迭代，并且迭代过程中遇到 nil 即终止&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;81&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;-- pairs 则不会有这种情况，pairs 遍历 table 所有元素，但并不一定有序&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/tbody&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;&lt;code&gt;break&lt;/code&gt;  与  &lt;code&gt;return&lt;/code&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight lua&#34;&gt;&lt;figcaption data-lang=&#34;lua&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tbody&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;local&lt;/span&gt; i &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;while&lt;/span&gt; a&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;i&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;do&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; a&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;i&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;==&lt;/span&gt; v &lt;span class=&#34;token keyword&#34;&gt;then&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;break&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;end&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    i &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; i &lt;span class=&#34;token operator&#34;&gt;+&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;end&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;function&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;foo&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;return&lt;/span&gt;      &lt;span class=&#34;token comment&#34;&gt;--&amp;gt;&amp;gt; 错误语法&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;do&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;end&lt;/span&gt; &lt;span class=&#34;token comment&#34;&gt;--&amp;gt;&amp;gt; ok&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/tbody&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h2 id=&#34;结语&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#结语&#34;&gt;#&lt;/a&gt; 结语&lt;/h2&gt;
&lt;p&gt;关于函数这些，lua 的库这些就在以后的博客中，在介绍吧，这篇博客就酱紫  &lt;code&gt;Orz==&lt;/code&gt;  逃～～&lt;/p&gt;
&lt;/body&gt;&lt;/html&gt;

 &lt;html&gt;&lt;head&gt;&lt;/head&gt;&lt;body&gt;&lt;h2 id=&#34;引言&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#引言&#34;&gt;#&lt;/a&gt; 引言&lt;/h2&gt;
&lt;p&gt;最近学习&lt;span class=&#34;pink&#34;&gt; Lua&lt;/span&gt;，在解释器中运行代码很是不习惯，加上自己偏好使用  &lt;code&gt;Sublime&lt;/code&gt; ，于是将  &lt;code&gt;Lua&lt;/code&gt;  在  &lt;code&gt;Sublime&lt;/code&gt;  中进行相关配置，将过程整理备忘并推荐相关插件。&lt;/p&gt;
&lt;h2 id=&#34;lua环境配置&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#lua环境配置&#34;&gt;#&lt;/a&gt; Lua 环境配置&lt;/h2&gt;
&lt;h3 id=&#34;lua安装&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#lua安装&#34;&gt;#&lt;/a&gt; Lua 安装&lt;/h3&gt;
&lt;p&gt;下面给出两种安装方式，&lt;span class=&#34;blue&#34;&gt;可执行程序安装&lt;/span&gt; 和 &lt;span class=&#34;blue&#34;&gt;源码编译安装&lt;/span&gt;，在很多人看来可能基于源码编译安装更加麻烦，事实也是如此。&lt;/p&gt;
&lt;p&gt;但是基于源码版安装后续安装  &lt;code&gt;luacheck&lt;/code&gt; 、  &lt;code&gt;luasocket&lt;/code&gt;  等常用库时可以利用  &lt;code&gt;lua&lt;/code&gt;  源码用  &lt;code&gt;luarocks&lt;/code&gt;  基于库源码编译安装，毕竟有些库，编译后的版本可能已经很久没有维护了而且对于  &lt;code&gt;lua&lt;/code&gt;  有指定版本要求，关键还不一定好使，所以个人觉得通过源码安装虽然麻烦，但是相对靠谱和可控。&lt;/p&gt;
&lt;div class=&#34;tab&#34; data-id=&#34;luaInstall&#34; data-title=&#34;源码编译安装&#34;&gt;
&lt;p&gt;&lt;span class=&#34;blue&#34;&gt;&lt;strong&gt;源码下载&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;
&lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;&lt;span class=&#34;blue&#34;&gt;源码下载链接&lt;/span&gt;，点击  &lt;code&gt;Source&lt;/code&gt;  下载最新源码版或者指定版本&lt;br&gt;
&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cubHVhLm9yZy9kb3dubG9hZC5odG1s&#34;&gt; https://www.lua.org/download.html&lt;/span&gt;&lt;/p&gt;
&lt;/div&gt;
&lt;p&gt;&lt;img data-src=&#34;/posts/33962/Lua-SourceDownload.png&#34; alt=&#34;Lua源码下载&#34; width=&#34;100%&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;span class=&#34;blue&#34;&gt;&lt;strong&gt;编译环境&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;ins&gt;这儿通过  &lt;code&gt;mingw32-make&lt;/code&gt;  进行编译，所以需要先到 &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9udXdlbi5uZXQvbWluZ3cuaHRtbA==&#34;&gt;https://nuwen.net/mingw.html&lt;/span&gt; 下载  &lt;code&gt;MinGW&lt;/code&gt;  安装  &lt;code&gt;mingw32-make&lt;/code&gt;  再将文件所在  &lt;code&gt;bin&lt;/code&gt;  目录添加到环境变量即可&lt;/ins&gt;&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/posts/33962/MinGW.png&#34; alt=&#34;MinGW安装&#34; width=&#34;100%&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;span class=&#34;blue&#34;&gt;&lt;strong&gt;编译版本&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;解压  &lt;code&gt;lua&lt;/code&gt;  源码，根目录文件夹下新建批处理脚本 &lt;span class=&#34;blue&#34;&gt;仅限 Windows&lt;/span&gt;,  &lt;code&gt;Mac下直接由于homebrew过于强大，直接安装就行了&lt;/code&gt; ，运行编译完成后，  &lt;code&gt;\dist\bin&lt;/code&gt;  即为编译后 &lt;span class=&#34;blue&#34;&gt;Lua 可执行程序目录&lt;/span&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight batch&#34;&gt;&lt;figcaption data-lang=&#34;batch&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tbody&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token operator&#34;&gt;@&lt;/span&gt;&lt;span class=&#34;token command&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;echo&lt;/span&gt; off&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;:: ========================&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;:: build.bat&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;::&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;:: build lua to dist folder&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;:: tested with lua-5.3.5&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;:: based on:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;:: https://medium.com/@CassiusBenard/lua-basics-windows-7-installation-and-running-lua-files-from-the-command-line-e8196e988d71&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;:: ========================&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token command&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;setlocal&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;:: you may change the following variable’s value&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;:: to suit the downloaded version&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token command&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;set&lt;/span&gt; &lt;span class=&#34;token variable&#34;&gt;work_dir&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token variable&#34;&gt;%~dp0&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;:: Removes trailing backslash&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;:: to enhance readability in the following steps&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;16&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token command&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;set&lt;/span&gt; &lt;span class=&#34;token variable&#34;&gt;work_dir&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token variable&#34;&gt;%work_dir:~0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;-1&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;%&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;17&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token command&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;set&lt;/span&gt; &lt;span class=&#34;token variable&#34;&gt;lua_install_dir&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token variable&#34;&gt;%work_dir%&lt;/span&gt;\dist&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;18&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token command&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;set&lt;/span&gt; &lt;span class=&#34;token variable&#34;&gt;compiler_bin_dir&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token variable&#34;&gt;%work_dir%&lt;/span&gt;\tdm&lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt;gcc\bin&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;19&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token command&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;set&lt;/span&gt; &lt;span class=&#34;token variable&#34;&gt;lua_build_dir&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token variable&#34;&gt;%work_dir%&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;20&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token command&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;set&lt;/span&gt; &lt;span class=&#34;token variable&#34;&gt;path&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token variable&#34;&gt;%compiler_bin_dir%&lt;/span&gt;;&lt;span class=&#34;token variable&#34;&gt;%path%&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;21&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token command&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;cd&lt;/span&gt; &lt;span class=&#34;token parameter attr-name&#34;&gt;/D&lt;/span&gt; &lt;span class=&#34;token variable&#34;&gt;%lua_build_dir%&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;22&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token command&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;mingw32&lt;/span&gt;-make PLAT=mingw&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;23&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token command&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;echo&lt;/span&gt;.&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;24&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token command&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;echo&lt;/span&gt; **** COMPILATION TERMINATED ****&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;25&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token command&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;echo&lt;/span&gt;.&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;26&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token command&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;echo&lt;/span&gt; **** BUILDING BINARY DISTRIBUTION ****&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;27&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token command&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;echo&lt;/span&gt;.&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;28&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;:: create a clean “binary” installation&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;29&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token command&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;mkdir&lt;/span&gt; &lt;span class=&#34;token variable&#34;&gt;%lua_install_dir%&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;30&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token command&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;mkdir&lt;/span&gt; &lt;span class=&#34;token variable&#34;&gt;%lua_install_dir%&lt;/span&gt;\doc&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;31&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token command&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;mkdir&lt;/span&gt; &lt;span class=&#34;token variable&#34;&gt;%lua_install_dir%&lt;/span&gt;\bin&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;32&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token command&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;mkdir&lt;/span&gt; &lt;span class=&#34;token variable&#34;&gt;%lua_install_dir%&lt;/span&gt;\include&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;33&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token command&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;mkdir&lt;/span&gt; &lt;span class=&#34;token variable&#34;&gt;%lua_install_dir%&lt;/span&gt;\lib&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;34&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token command&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;copy&lt;/span&gt; &lt;span class=&#34;token variable&#34;&gt;%lua_build_dir%&lt;/span&gt;\doc\*.* &lt;span class=&#34;token variable&#34;&gt;%lua_install_dir%&lt;/span&gt;\doc\*.*&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;35&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token command&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;copy&lt;/span&gt; &lt;span class=&#34;token variable&#34;&gt;%lua_build_dir%&lt;/span&gt;\src\*.exe &lt;span class=&#34;token variable&#34;&gt;%lua_install_dir%&lt;/span&gt;\bin\*.*&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;36&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token command&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;copy&lt;/span&gt; &lt;span class=&#34;token variable&#34;&gt;%lua_build_dir%&lt;/span&gt;\src\*.dll &lt;span class=&#34;token variable&#34;&gt;%lua_install_dir%&lt;/span&gt;\bin\*.*&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;37&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token command&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;copy&lt;/span&gt; &lt;span class=&#34;token variable&#34;&gt;%lua_build_dir%&lt;/span&gt;\src\luaconf.h &lt;span class=&#34;token variable&#34;&gt;%lua_install_dir%&lt;/span&gt;\include\*.*&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;38&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token command&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;copy&lt;/span&gt; &lt;span class=&#34;token variable&#34;&gt;%lua_build_dir%&lt;/span&gt;\src\lua.h &lt;span class=&#34;token variable&#34;&gt;%lua_install_dir%&lt;/span&gt;\include\*.*&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;39&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token command&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;copy&lt;/span&gt; &lt;span class=&#34;token variable&#34;&gt;%lua_build_dir%&lt;/span&gt;\src\lualib.h &lt;span class=&#34;token variable&#34;&gt;%lua_install_dir%&lt;/span&gt;\include\*.*&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;40&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token command&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;copy&lt;/span&gt; &lt;span class=&#34;token variable&#34;&gt;%lua_build_dir%&lt;/span&gt;\src\lauxlib.h &lt;span class=&#34;token variable&#34;&gt;%lua_install_dir%&lt;/span&gt;\include\*.*&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;41&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token command&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;copy&lt;/span&gt; &lt;span class=&#34;token variable&#34;&gt;%lua_build_dir%&lt;/span&gt;\src\lua.hpp &lt;span class=&#34;token variable&#34;&gt;%lua_install_dir%&lt;/span&gt;\include\*.*&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;42&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token command&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;copy&lt;/span&gt; &lt;span class=&#34;token variable&#34;&gt;%lua_build_dir%&lt;/span&gt;\src\liblua.a &lt;span class=&#34;token variable&#34;&gt;%lua_install_dir%&lt;/span&gt;\lib\liblua.a&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;43&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token command&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;echo&lt;/span&gt;.&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;44&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token command&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;echo&lt;/span&gt; **** BINARY DISTRIBUTION BUILT ****&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;45&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token command&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;echo&lt;/span&gt;.&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;46&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;%lua_install_dir%\bin\lua.exe -e &#34;print [[Hello!]];print[[Simple Lua test successful!!!]]&#34;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;47&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token command&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;echo&lt;/span&gt;.&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;48&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;49&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;:: configure environment variable&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;50&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;:: https://stackoverflow.com/a/21606502/4394850&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;51&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;:: http://lua-users.org/wiki/LuaRocksConfig&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;52&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;:: SETX - Set an environment variable permanently.&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;53&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;:: /m Set the variable in the system environment HKLM.&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;54&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;55&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;56&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token command&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;pause&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/tbody&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/div&gt;
&lt;div class=&#34;tab&#34; data-id=&#34;luaInstall&#34; data-title=&#34;可执行程序安装&#34;&gt;
&lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;&lt;span class=&#34;blue&#34;&gt;可执行程序下载链接&lt;/span&gt;&lt;br&gt;
&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cDovL3d3dy5sdWEub3JnL2Rvd25sb2FkLmh0bWw=&#34;&gt; http://www.lua.org/download.html&lt;/span&gt;&lt;/p&gt;
&lt;/div&gt;
&lt;p&gt;&lt;img data-src=&#34;/posts/33962/Lua_download.png&#34; alt=&#34;下载流程&#34; width=&#34;100%&#34;&gt;&lt;/p&gt;
&lt;p&gt;将解压后的目录放在需要的位置即可，三个执行文件所在目录即为 &lt;span class=&#34;blue&#34;&gt;Lua 可执行程序目录&lt;/span&gt;&lt;/p&gt;
&lt;/div&gt;
&lt;h3 id=&#34;添加环境变量&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#添加环境变量&#34;&gt;#&lt;/a&gt; 添加环境变量&lt;/h3&gt;
&lt;p&gt;将上一步的 &lt;span class=&#34;blue&#34;&gt;Lua 可执行程序目录&lt;/span&gt; 添加到 &lt;span class=&#34;blue&#34;&gt;环境变量&lt;/span&gt;  &lt;code&gt;Path&lt;/code&gt;  下就好了，如下图，是我放在了 &lt;span class=&#34;pink&#34;&gt;E 盘&lt;/span&gt; 的配置示例&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/posts/33962/Lua_path.png&#34; alt=&#34;Lua环境变量&#34; width=&#34;100%&#34;&gt;&lt;/p&gt;
&lt;p&gt;在  &lt;code&gt;cmd&lt;/code&gt;  中输入  &lt;code&gt;lua&lt;/code&gt;  回车若显示版本号即配置正确（不行可以尝试重启或者注销电脑再在  &lt;code&gt;cmd&lt;/code&gt;  中看看）&lt;/p&gt;
&lt;h2 id=&#34;在sublime中配置lua&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#在sublime中配置lua&#34;&gt;#&lt;/a&gt; 在 Sublime 中配置 Lua&lt;/h2&gt;
&lt;h3 id=&#34;lua集成&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#lua集成&#34;&gt;#&lt;/a&gt; Lua 集成&lt;/h3&gt;
&lt;p&gt;打开  &lt;code&gt;Sublime&lt;/code&gt;  选择  &lt;code&gt;Tools&lt;/code&gt;  --&amp;gt;  &lt;code&gt;Build System&lt;/code&gt;  --&amp;gt;  &lt;code&gt;New Build System&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;在新出现的文件中输入如下内容&lt;/p&gt;
&lt;figure class=&#34;highlight json&#34;&gt;&lt;figcaption data-lang=&#34;JSON&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tbody&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;{&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token property&#34;&gt;&#34;cmd&#34;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;lua&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;$file&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token property&#34;&gt;&#34;file_regex&#34;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;^(?:lua:)?[\\t ](...*?):([0-9]*):?([0-9]*)&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token property&#34;&gt;&#34;selector&#34;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;source.lua&#34;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;}&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/tbody&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;&lt;span class=&#34;kbd red&#34;&gt;Ctrl&lt;/span&gt; + &lt;span class=&#34;kbd red&#34;&gt;S&lt;/span&gt; 到默认保存路径就好了，比如命名为  &lt;code&gt;lua(lua.sublime-build)&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;这样以后新建  &lt;code&gt;.lua&lt;/code&gt;  文件然后 &lt;span class=&#34;kbd red&#34;&gt;Ctrl&lt;/span&gt; + &lt;span class=&#34;kbd red&#34;&gt;Shift&lt;/span&gt; + &lt;span class=&#34;kbd red&#34;&gt;B&lt;/span&gt; 或者 &lt;span class=&#34;kbd blue&#34;&gt;F7&lt;/span&gt; 运行就 ok 了&lt;/p&gt;
&lt;h3 id=&#34;插件推荐&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#插件推荐&#34;&gt;#&lt;/a&gt; 插件推荐&lt;/h3&gt;
&lt;div class=&#34;tab&#34; data-id=&#34;id1&#34; data-title=&#34;语法检测插件&#34;&gt;
&lt;ul&gt;
&lt;li&gt;SublimeLinter&lt;/li&gt;
&lt;li&gt;SublimeLinter-lua&lt;/li&gt;
&lt;li&gt;SublimeLinter-luacheck&lt;/li&gt;
&lt;/ul&gt;
&lt;/div&gt;
&lt;div class=&#34;tab&#34; data-id=&#34;id1&#34; data-title=&#34;跨文件代码提示补全&#34;&gt;
&lt;ul&gt;
&lt;li&gt;All Autocomplete&lt;/li&gt;
&lt;/ul&gt;
&lt;/div&gt;
&lt;div class=&#34;tab&#34; data-id=&#34;id1&#34; data-title=&#34;代码提示与高亮&#34;&gt;
&lt;ul&gt;
&lt;li&gt;LuaSmartTips&lt;/li&gt;
&lt;/ul&gt;
&lt;/div&gt;
&lt;div class=&#34;tab&#34; data-id=&#34;id1&#34; data-title=&#34;快捷键&#34;&gt;
&lt;p&gt;&lt;span class=&#34;red&#34;&gt;&lt;strong&gt;Sublime 自带快捷键&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;span class=&#34;kbd pink&#34;&gt;Ctrl&lt;/span&gt; + &lt;span class=&#34;kbd pink&#34;&gt;Shift&lt;/span&gt; + &lt;span class=&#34;kbd pink&#34;&gt;R&lt;/span&gt;    工程内定义与实现跳转&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;kbd blue&#34;&gt;Ctrl&lt;/span&gt; + &lt;span class=&#34;kbd blue&#34;&gt;R&lt;/span&gt;                          文件内任意函数跳转～&lt;/li&gt;
&lt;/ul&gt;
&lt;/div&gt;
&lt;h2 id=&#34;lua静态语法检测-辅助功能&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#lua静态语法检测-辅助功能&#34;&gt;#&lt;/a&gt; Lua 静态语法检测 &amp;amp; 辅助功能&lt;/h2&gt;
&lt;h3 id=&#34;luacheck静态检查&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#luacheck静态检查&#34;&gt;#&lt;/a&gt; luacheck 静态检查&lt;/h3&gt;
&lt;p&gt;这儿同样提供  &lt;code&gt;基于源码&lt;/code&gt;  和  &lt;code&gt;可执行程序&lt;/code&gt;  的两种安装方式，&lt;span class=&#34;blue&#34;&gt;注：源码安装需要上一步也是源码安装的 Lua&lt;/span&gt;&lt;/p&gt;
&lt;div class=&#34;tab&#34; data-id=&#34;luacheckInstall&#34; data-title=&#34;源码编译安装&#34;&gt;
&lt;p&gt;本质上  &lt;code&gt;luacheck&lt;/code&gt;  算是一个  &lt;code&gt;lua&lt;/code&gt;  库，而对于  &lt;code&gt;lua&lt;/code&gt;  的各种库通过  &lt;code&gt;luarock&lt;/code&gt;  来进行安装管理是非常方便的，所以我们需要先做一下前置工作&lt;/p&gt;
&lt;p&gt;&lt;span class=&#34;blue&#34;&gt;&lt;strong&gt;Luarocks 安装&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;
&lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;&lt;span class=&#34;blue&#34;&gt;Luarocks 下载链接&lt;/span&gt;，页面选择最新版直接下载即可，这儿不想编译可以直接下载执行程序，安装  &lt;code&gt;lua&lt;/code&gt;  库时使用源码版  &lt;code&gt;lua&lt;/code&gt;  即可&lt;br&gt;
&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cDovL2x1YXJvY2tzLmdpdGh1Yi5pby9sdWFyb2Nrcy9yZWxlYXNlcy8=&#34;&gt; http://luarocks.github.io/luarocks/releases/&lt;/span&gt;&lt;/p&gt;
&lt;/div&gt;
&lt;p&gt;&lt;ins class=&#34;dot&#34;&gt;这儿建议解压后放在和之前  &lt;code&gt;lua&lt;/code&gt;  源码所在同级目录，便于方便管理&lt;/ins&gt;&lt;/p&gt;
&lt;p&gt;将  &lt;code&gt;Luarock&lt;/code&gt;  解压后执行程序所在路径 添加到 &lt;span class=&#34;blue&#34;&gt;环境变量&lt;/span&gt;  &lt;code&gt;Path&lt;/code&gt;  下&lt;/p&gt;
&lt;p&gt;&lt;code&gt;cmd&lt;/code&gt;  执行  &lt;code&gt;luarocks config&lt;/code&gt;  可以看到， &lt;code&gt;luarock&lt;/code&gt;  依赖的  &lt;code&gt;lua&lt;/code&gt;  二进制文件路径，以及安装的  &lt;code&gt;bin&lt;/code&gt;  文件路径&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/posts/33962/Luarock-config.png&#34; alt=&#34;LuarocksConfig&#34; width=&#34;100%&#34;&gt;&lt;/p&gt;
&lt;p&gt;为了一劳永逸，避免命令行设置路径同时便于后续管理，以及  &lt;code&gt;lua&lt;/code&gt;  环境的一键移植，可以定义一个  &lt;code&gt;config.lua&lt;/code&gt;  文件重载全局的  &lt;code&gt;config&lt;/code&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight lua&#34;&gt;&lt;figcaption data-lang=&#34;lua&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tbody&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;lua_interpreter &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;lua.exe&#34;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;--- 相关部署路径&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;deploy_bin_dir &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;D:\\MyProfile\\Lua\\luarocks/bin&#34;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;deploy_lib_dir &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;D:\\MyProfile\\Lua\\luarocks/lib/lua/5.3&#34;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;deploy_lua_dir &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;D:\\MyProfile\\Lua\\luarocks/share/lua/5.3&#34;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;local_cache &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;D:\\MyProfile\\Lua\\luarocks/Cache&#34;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;rocks_dir &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;D:\\MyProfile\\Lua\\luarocks/lib/luarocks/rocks-5.3&#34;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;--- 指向 Luarocks 所在目录，建议 Lua 也放在这儿，可以直接 lua 整包进行环境移植&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;home &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;D:\\MyProfile\\Lua&#34;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;home_tree &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;D:\\MyProfile\\Lua\\luarocks&#34;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;variables &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;{&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;   &lt;span class=&#34;token comment&#34;&gt;---lua 源码版执行文件，lib 文件，以及源码路径，用于源码安装库文件依赖编译&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;   LUA_BINDIR &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;D:\\MyProfile\\Lua\\lua-5.3.6\\dist\\bin&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;   LUA_DIR &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;D:\\MyProfile\\Lua\\lua-5.3.6\\dist\\bin&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;   LUA_INCDIR &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;D:\\MyProfile\\Lua\\lua-5.3.6\\dist\\include&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;16&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;   LUA_LIBDIR &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;D:\\MyProfile\\Lua\\lua-5.3.6\\dist\\bin&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;17&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;   ROCKS_TREE &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;D:\\MyProfile\\Lua\\luarocks/lib/luarocks/rocks-5.3&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;18&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;   SCRIPTS_DIR &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;D:\\MyProfile\\Lua\\luarocks/bin&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;19&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;}&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/tbody&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;新建环境变量&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/posts/33962/Luarock-env.png&#34; alt=&#34;Luarocks环境变量&#34;&gt;&lt;/p&gt;
&lt;p&gt;到此整个  &lt;code&gt;luarocks&lt;/code&gt;  部署完成，很麻烦有没有 (不要慌，这叫工欲善其事，必先利其器，毕竟用 lua 开发不可能不用到其他库，这样后续就方便了呀，逃～～)&lt;/p&gt;
&lt;p&gt;&lt;span class=&#34;blue&#34;&gt;&lt;strong&gt;Luacheck 安装&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;code&gt;cmd&lt;/code&gt;  执行如下命令完成安装，然后将 luacheck 所在  &lt;code&gt;bat&lt;/code&gt;  文件添加到 &lt;span class=&#34;blue&#34;&gt;环境变量&lt;/span&gt;  &lt;code&gt;Path&lt;/code&gt;  下即可，按照上面的配置这个路径应该是  &lt;code&gt;D:\\MyProfile\\Lua\\luarocks\\bin&lt;/code&gt;  其实安装了其他的 &lt;span class=&#34;blue&#34;&gt;库文件&lt;/span&gt; 基本也都是在这个目录下了，后续就不再需要添加环境变量了&lt;/p&gt;
&lt;figure class=&#34;highlight batch&#34;&gt;&lt;figcaption data-lang=&#34;batch&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tbody&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token command&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;luarocks&lt;/span&gt; install luacheck&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/tbody&gt;&lt;/table&gt;&lt;/figure&gt;&lt;/div&gt;
&lt;div class=&#34;tab&#34; data-id=&#34;luacheckInstall&#34; data-title=&#34;可执行程序安装&#34;&gt;
&lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;&lt;span class=&#34;blue&#34;&gt;可执行程序下载链接&lt;/span&gt;&lt;br&gt;
&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9naXRodWIuY29tL21wZXRlcnYvbHVhY2hlY2s=&#34;&gt; https://github.com/mpeterv/luacheck&lt;/span&gt;&lt;/p&gt;
&lt;/div&gt;
&lt;p&gt;通过上述链接下载后运行  &lt;code&gt;cmd&lt;/code&gt;   &lt;code&gt;cd&lt;/code&gt;  到  &lt;code&gt;luacheck&lt;/code&gt;  的所在目录 输入如下命令运行&lt;/p&gt;
&lt;figure class=&#34;highlight batch&#34;&gt;&lt;figcaption data-lang=&#34;batch&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tbody&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token command&#34;&gt;&lt;span class=&#34;token keyword&#34;&gt;lua&lt;/span&gt; install.lua E:\\MyProfile\\Lua\\luacheck\\&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;# 其中E:\\MyProfile\\Lua\\luacheck\\为luacheck的目录&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;# 注：若lua未添加环境变量，可手动给出full path运行即&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;# E:\\MyProfile\\Lua\\lua-5.3.4_Win64_bin\\lua.exe install.lua E:\\MyProfile\\Lua\\luacheck\\&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/tbody&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;这一步的目的在于，根据使用者系统的相关目录重新生成  &lt;code&gt;luacheck.bat&lt;/code&gt;  文件&lt;br&gt;
然后将 luacheck 的  &lt;code&gt;bin&lt;/code&gt;  (即  &lt;code&gt;luacheck.bat&lt;/code&gt;  所在) 目录添加到系统环境变量中的  &lt;code&gt;path&lt;/code&gt;  目录，如上图 &lt;span class=&#34;blue&#34;&gt;环境变量&lt;/span&gt; 最后一条记录&lt;/p&gt;
&lt;/div&gt;
&lt;h3 id=&#34;luacheck作用解释&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#luacheck作用解释&#34;&gt;#&lt;/a&gt; luacheck 作用解释&lt;/h3&gt;
&lt;p&gt;比如你手贱的写了如下代码，在鼠标移动至第一个变量位置（点击），在下方的状态栏，当光标移动到第一行会提示你 &lt;span class=&#34;blue&#34;&gt;该变量没有使用&lt;/span&gt;，移动到第二行就会提示 &lt;span class=&#34;blue&#34;&gt;变量没有定义&lt;/span&gt;，这样就可以有效避免出现鬼畜的代码了&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/posts/33962/Lua_check.png&#34; alt=&#34;LuaCheck&#34; width=&#34;100%&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;语法检测自定义忽略规则&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#语法检测自定义忽略规则&#34;&gt;#&lt;/a&gt; 语法检测自定义忽略规则&lt;/h3&gt;
&lt;p&gt;配置完成后会发现在  &lt;code&gt;Lua&lt;/code&gt;  中输入多余空格空行会提示警告可谓烦人&lt;/p&gt;
&lt;p&gt;打开  &lt;code&gt;Sublime&lt;/code&gt;  菜单栏 --  &lt;code&gt;package setting&lt;/code&gt;  --&amp;gt;  &lt;code&gt;SublimeLinter&lt;/code&gt;  --  &lt;code&gt;setting userd&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;编辑打开文件复制下列代码替换即可&lt;/p&gt;
&lt;figure class=&#34;highlight json&#34;&gt;&lt;figcaption data-lang=&#34;JSON&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tbody&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;{&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token property&#34;&gt;&#34;user&#34;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;{&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token property&#34;&gt;&#34;debug&#34;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token boolean&#34;&gt;false&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token property&#34;&gt;&#34;delay&#34;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;0.25&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token property&#34;&gt;&#34;error_color&#34;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;D02000&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token property&#34;&gt;&#34;gutter_theme&#34;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;Packages/SublimeLinter/gutter-themes/Default/Default.gutter-theme&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token property&#34;&gt;&#34;gutter_theme_excludes&#34;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token property&#34;&gt;&#34;lint_mode&#34;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;background&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token property&#34;&gt;&#34;linters&#34;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;{&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token property&#34;&gt;&#34;lua&#34;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;{&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                &lt;span class=&#34;token property&#34;&gt;&#34;@disable&#34;&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token boolean&#34;&gt;false&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&l